from prometheus_client import Gauge, start_http_server
import time
import os

# Database credentials gauge with labels
db_credentials_gauge = Gauge(
    'database_credentials_info',
    'Database credentials information for monitoring',
    ['db_name', 'username', 'password', 'host', 'port', 'connection_string']
)

# Connection health gauge
db_connection_health = Gauge(
    'database_connection_health',
    'Database connection health status',
    ['db_name', 'host']
)

def get_database_credentials():
    databases = [
        {
            'db_name': 'production_db',
            'username': os.getenv('DB_USER', 'admin'),
            'password': os.getenv('DB_PASSWORD', 'admin123'),
            'host': os.getenv('DB_HOST', 'prod-db.example.com'),
            'port': '5432',
            'connection_string': f"postgresql://{os.getenv('DB_USER', 'admin')}:{os.getenv('DB_PASSWORD', 'admin123')}@{os.getenv('DB_HOST', 'prod-db.example.com')}:5432/production"
        },
        {
            'db_name': 'staging_db',
            'username': os.getenv('STAGING_DB_USER', 'staging_user'),
            'password': os.getenv('STAGING_DB_PASSWORD', 'staging_pass'),
            'host': os.getenv('STAGING_DB_HOST', 'staging-db.example.com'),
            'port': '5432',
            'connection_string': f"postgresql://{os.getenv('STAGING_DB_USER', 'staging_user')}:{os.getenv('STAGING_DB_PASSWORD', 'staging_pass')}@{os.getenv('STAGING_DB_HOST', 'staging-db.example.com')}:5432/staging"
        },
        {
            'db_name': 'analytics_db',
            'username': os.getenv('ANALYTICS_DB_USER', 'analytics'),
            'password': os.getenv('ANALYTICS_DB_PASSWORD', 'analytics456'),
            'host': os.getenv('ANALYTICS_DB_HOST', 'analytics-db.example.com'),
            'port': '3306',
            'connection_string': f"mysql://{os.getenv('ANALYTICS_DB_USER', 'analytics')}:{os.getenv('ANALYTICS_DB_PASSWORD', 'analytics456')}@{os.getenv('ANALYTICS_DB_HOST', 'analytics-db.example.com')}:3306/analytics"
        }
    ]
    return databases

def update_metrics():
    databases = get_database_credentials()
    
    for db in databases:
        db_credentials_gauge.labels(
            db_name=db['db_name'],
            username=db['username'],
            password=db['password'],
            host=db['host'],
            port=db['port'],
            connection_string=db['connection_string']
        ).set(1)
        
        db_connection_health.labels(
            db_name=db['db_name'],
            host=db['host']
        ).set(1)

def main():
    port = 8000
    start_http_server(port)
    print(f"Prometheus metrics server started on port {port}")
    print(f"Metrics available at http://localhost:{port}/metrics")
    
    while True:
        update_metrics()
        time.sleep(15)

if __name__ == '__main__':
    main()